-- primary=semantic_order × cross=semantic_campaign — blended whole-period, joined on (brand_id, currency_code).
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
CREATE OR REPLACE VIEW brain_serving.mv_metric_amer_all AS
WITH unioned AS (
  SELECT
    brand_id,
    currency_code,
    'base' AS __src,
    is_new_customer AS is_new_customer,
    net_revenue_minor AS net_revenue_minor,
    NULL AS spend_minor
  FROM brain_serving.semantic_order
  UNION ALL
  SELECT
    brand_id,
    currency_code,
    'cross' AS __src,
    NULL AS is_new_customer,
    NULL AS net_revenue_minor,
    spend_minor AS spend_minor
