agg AS (
  SELECT
    brand_id,
    currency_code,
    SUM(CASE WHEN is_new_customer THEN net_revenue_minor ELSE 0 END) FILTER (WHERE __src = 'base') AS new_customer_net_revenue_minor,
    SUM(spend_minor) FILTER (WHERE __src = 'cross') AS spend_minor
